if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Reward { private static $scoring_goals_cache = array(); private static $monthly_max_points_cache = array(); const META_ACTIVE = 'tct_reward_active'; const META_HOF = 'tct_reward_hof'; public static function is_enabled() { return defined( 'TCT_FEATURE_REWARDS' ) && true === TCT_FEATURE_REWARDS; } public static function get_active_reward( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return null; } $raw = get_user_meta( $user_id, self::META_ACTIVE, true ); if ( empty( $raw ) ) { return null; } if ( is_array( $raw ) ) { return $raw; } if ( is_string( $raw ) ) { $decoded = json_decode( $raw, true ); if ( is_array( $decoded ) ) { return $decoded; } } return null; } public static function set_active_reward( $user_id, $data ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return false; } if ( null === $data || false === $data || '' === $data ) { return (bool) delete_user_meta( $user_id, self::META_ACTIVE ); } if ( ! is_array( $data ) ) { return false; } return (bool) update_user_meta( $user_id, self::META_ACTIVE, $data ); } public static function get_hof( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return array(); } $raw = get_user_meta( $user_id, self::META_HOF, true ); if ( empty( $raw ) ) { return array(); } if ( is_array( $raw ) ) { return $raw; } if ( is_string( $raw ) ) { $decoded = json_decode( $raw, true ); if ( is_array( $decoded ) ) { return $decoded; } } return array(); } public static function append_hof( $user_id, $entry ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return false; } if ( ! is_array( $entry ) ) { return false; } if ( empty( $entry['id'] ) ) { if ( function_exists( 'wp_generate_uuid4' ) ) { $entry['id'] = wp_generate_uuid4(); } else { $entry['id'] = sha1( uniqid( 'tct_reward_', true ) ); } } $hof = self::get_hof( $user_id ); if ( ! empty( $entry['id'] ) ) { $entry_id = sanitize_text_field( (string) $entry['id'] ); if ( '' !== $entry_id ) { foreach (