] ); return self::set_active_reward( $user_id, $reward ); } public static function delete_progress_variant_attachments( $user_id, $force_delete = true ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return 0; } $variants = self::get_progress_variants( $user_id ); if ( empty( $variants ) || ! is_array( $variants ) ) { return 0; } $deleted = 0; foreach ( $variants as $key => $attachment_id ) { $attachment_id = (int) $attachment_id; if ( $attachment_id <= 0 ) { continue; } $post = get_post( $attachment_id ); if ( ! $post || 'attachment' !== $post->post_type ) { continue; } $result = wp_delete_attachment( $attachment_id, $force_delete ); if ( $result ) { $deleted++; } } return $deleted; } public static function round_progress_to_step( $progress_pct ) { $pct = (float) $progress_pct; if ( $pct < 0 ) { $pct = 0; } if ( $pct >= 100 ) { return 100.0; } $step = 2.5; $rounded = round( $pct / $step ) * $step; if ( $rounded > 100 ) { $rounded = 100.0; } return $rounded; } public static function get_progress_variant_attachment_id( $user_id, $progress_pct ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return null; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { return null; } $original_id = isset( $reward['attachment_id'] ) ? (int) $reward['attachment_id'] : 0; if ( $original_id <= 0 ) { return null; } $rounded = self::round_progress_to_step( $progress_pct ); if ( $rounded >= 100.0 ) { return $original_id; } $variants = isset( $reward['progress_variants'] ) && is_array( $reward['progress_variants'] ) ? $reward['progress_variants'] : array(); if ( empty( $variants ) ) { return $original_id; } $key = self::progress_step_to_key( $rounded ); if ( isset( $variants[ $key ] ) ) { $variant_id = (int) $variants[ $key ]; if ( $variant_id > 0 ) { return $variant_id; } } $nearest_id = self::find_nearest_variant( $variants, $rounded ); if ( $nearest_id > 0 ) { return $nearest_id; } return $original_id; } public static function get_progress_variant_url( $user_id, $progress_pct, $size = 'medium' ) { $attachment_id = self::get_progress_variant_attachment_id( $user_id, $progress_pct ); if ( ! $attachment_id || $attachment_id <= 0 ) { return null; } $url = wp_get_attachment_image_url( $attachment_id, $size ); if ( ! $url ) { return null; } return $url; } private static function progress_step_to_key( $step ) { $step = (float) $step; if ( floor( $step ) == $step ) { return (string) (int) $step; } return (string) $step; } private static function find_nearest_variant( $variants, $target ) { if ( empty( $variants ) ) { return 0; } $target = (float) $target; $best_id = 0; $best_distance = PHP_FLOAT_MAX; foreach ( $variants as $key => $attachment_id ) { $attachment_id = (int) $attachment_id; if ( $attachment_id <= 0 ) { continue; } $level = (float) $key; $distance = abs( $level - $target ); if ( $distance < $best_distance || ( $distance === $best_distance && $level < $target ) ) { $best_distance = $distance; $best_id = $attachment_id; } } return $best_id; } const CRON_HOOK_PROGRESS_GENERATION = 'tct_reward_progress_generation'; const CRON_SCHEDULE_EVERY_MINUTE = 'tct_every_minute'; const JOB_STATUS_PENDING = 'pending'; const JOB_STATUS_RUNNING = 'running'; const JOB_STATUS_COMPLETE = 'complete'; const JOB_STATUS_ERROR = 'error'; const JOB_MAX_RETRIES = 5; public static function get_generation_job( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return null; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { return null; } if ( ! isset( $reward['progress_generation_job'] ) || ! is_array( $reward['progress_generation_job'] ) ) { return null; } return $reward['progress_generation_job']; } public static function set_generation_job( $user_id, $job ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return false; } if ( ! is_array( $job ) ) { return false; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { return false; } $reward['progress_generation_job'] = $job; return self::set_active_reward( $user_id, $reward ); } public static function clear_generation_job( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return false; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { return false; } if ( ! isset( $reward['progress_generation_job'] ) ) { return true; } unset( $reward['progress_generation_job'] ); return self::set_active_reward( $user_id, $reward ); } public static function queue_generation_job( $user_id ) { $user_id = (int) $user_id; $result = array( 'ok' => false, 'error' => '', 'job' => null, ); if ( $user_id <= 0 ) { $result['error'] = 'Invalid user ID.'; return $result; } if ( ! class_exists( 'TCT_Admin' ) || ! TCT_Admin::is_progress_images_enabled() ) { $result['error'] = 'Progressive reward images feature is disabled.'; return $result; } if ( class_exists( 'TCT_Reward_Progress_Generator' ) && is_callable( array( 'TCT_Reward_Progress_Generator', 'check_programmatic_prereqs' ) ) ) { $pre = TCT_Reward_Progress_Generator::check_programmatic_prereqs(); if ( empty( $pre['ok'] ) ) { $result['error'] = isset( $pre['error'] ) && '' !== (string) $pre['error'] ? (string) $pre['error'] : 'Reward progress image generator prerequisites are not met.'; return $result; } } else { $result['error'] = 'Reward progress generator is not available.'; return $result; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { $result['error'] = 'No active reward configured.'; return $result; } $attachment_id = isset( $reward['attachment_id'] ) ? (int) $reward['attachment_id'] : 0; if ( $attachment_id <= 0 ) { $result['error'] = 'Reward has no image attached.'; return $result; } $now = time(); $job = array( 'status' => self::JOB_STATUS_PENDING, 'current_step' => 0, 'steps' => self::PROGRESS_STEPS, 'started_at' => $now, 'updated_at' => $now, 'last_error' => '', 'retry_count' => 0, ); $saved = self::set_generation_job( $user_id, $job ); if ( ! $saved ) { $result['error'] = 'Failed to save generation job.'; return $result; } self::ensure_cron_scheduled(); $result['ok'] = true; $result['job'] = $job; return $result; } public static function ensure_cron_scheduled() { if ( ! wp_next_scheduled( self::CRON_HOOK_PROGRESS_GENERATION ) ) { wp_schedule_event( time() + 30, self::CRON_SCHEDULE_EVERY_MINUTE, self::CRON_HOOK_PROGRESS_GENERATION ); } } public static function unschedule_cron() { $timestamp = wp_next_scheduled( self::CRON_HOOK_PROGRESS_GENERATION ); while ( $timestamp ) { wp_unschedule_event( $timestamp, self::CRON_HOOK_PROGRESS_GENERATION ); $timestamp = wp_next_scheduled( self::CRON_HOOK_PROGRESS_GENERATION ); } } public static function add_cron_schedule( $schedules ) { if ( ! isset( $schedules[ self::CRON_SCHEDULE_EVERY_MINUTE ] ) ) { $schedules[ self::CRON_SCHEDULE_EVERY_MINUTE ] = array( 'interval' => 60, 'display' => 'Every Minute (TCT Reward Progress)', ); } return $schedules; } public static function has_active_generation_job( $user_id ) { $job = self::get_generation_job( $user_id ); if ( ! is_array( $job ) ) { return false; } $status = isset( $job['status'] ) ? $job['status'] : ''; return in_array( $status, array( self::JOB_STATUS_PENDING, self::JOB_STATUS_RUNNING ), true ); } public static function get_generation_job_progress( $user_id ) { $result = array( 'status' => '', 'current' => 0, 'total' => count( self::PROGRESS_STEPS ), 'message' => '', 'error_type' => '', 'retry_count' => 0, ); $job = self::get_generation_job( $user_id ); if ( ! is_array( $job ) ) { $result['message'] = 'No generation job.'; return $result; } $status = isset( $job['status'] ) ? $job['status'] : ''; $current_step = isset( $job['current_step'] ) ? (int) $job['current_step'] : 0; $last_error = isset( $job['last_error'] ) ? $job['last_error'] : ''; $error_type = isset( $job['error_type'] ) ? $job['error_type'] : ''; $retry_count = isset( $job['retry_count'] ) ? (int) $job['retry_count'] : 0; $result['status'] = $status; $result['current'] = $curr