ror'] = 'Invalid user.'; return $out; } if ( ! class_exists( 'TCT_Ledger' ) || ! is_callable( array( 'TCT_Ledger', 'insert_custom_event' ) ) ) { $out['error'] = 'Ledger helper missing (insert_custom_event).'; return $out; } $reward = self::get_active_reward( $user_id ); if ( ! is_array( $reward ) || empty( $reward ) ) { $out['error'] = 'No active reward.'; return $out; } $created_at_utc = ''; if ( isset( $reward['created_at_utc'] ) && is_string( $reward['created_at_utc'] ) ) { $created_at_utc = trim( (string) $reward['created_at_utc'] ); } if ( '' === $created_at_utc ) { $created_at_utc = gmdate( 'Y-m-d H:i:s' ); } $hash_before = is_string( $hash_before ) ? trim( (string) $hash_before ) : ''; $hash_after = is_string( $hash_after ) ? trim( (string) $hash_after ) : ''; $context = is_string( $context ) ? trim( (string) $context ) : ''; $occurred_at = is_string( $occurred_at_utc_mysql ) ? trim( (string) $occurred_at_utc_mysql ) : ''; if ( '' === $occurred_at || '0000-00-00 00:00:00' === $occurred_at || false === strtotime( $occurred_at . ' UTC' ) ) { $occurred_at = current_time( 'mysql', true ); } $event_key = 'reward_rebase_' . sha1( implode( '|', array( (string) $user_id, $created_at_utc, $hash_before, $hash_after, $occurred_at ) ) ); $out['event_key'] = $event_key; $post = self::compute_reward_progress( $user_id, $reward ); if ( ! is_array( $post ) ) { $out['error'] = 'Could not compute post-change reward progress.'; return $out; } $post_errors = ( isset( $post['errors'] ) && is_array( $post['errors'] ) ) ? $post['errors'] : array(); if ( ! empty( $post_errors ) ) { $out['error'] = 'Post-change reward progress has errors: ' . implode( ' | ', array_map( 'sanitize_text_field', $post_errors ) ); return $out; } $earned_post = isset( $post['earned_points'] ) ? (int) $post['earned_points'] : 0; $target_post = isset( $post['target_points'] ) ? (int) $post['target_points'] : 0; $out['post_target'] = $target_post; $out['post_earned'] = $earned_post; if ( $target_post <= 0 ) {